import anthropic
import base64
from pathlib import Path

client = anthropic.Anthropic()  # uses ANTHROPIC_API_KEY env var

def read_text_from_screenshot(image_path: str) -> dict:
    """Extract all visible text from a screenshot and return it as JSON."""
    image_data = base64.standard_b64encode(Path(image_path).read_bytes()).decode("utf-8")

    message = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=1024,
        messages=[
            {
                "role": "user",
                "content": [
                    {
                        "type": "image",
                        "source": {
                            "type": "base64",
                            "media_type": "image/png",
                            "data": image_data,
                        },
                    },
                    {
                        "type": "text",
                        "text": (
                            "This is a screenshot of a web page. "
                            "Extract all visible text, preserving the reading order. "
                            "Return JSON with two fields: "
                            '{"heading": "<main heading text>", "body_text": ["<line1>", "<line2>", ...]}. '
                            "Include only text that is clearly readable. "
                            "Do not add explanations outside the JSON object."
                        ),
                    },
                ],
            }
        ],
    )
    import json
    # The response content is a list; first block is the text block.
    return json.loads(message.content[0].text)


# Usage
result = read_text_from_screenshot("page_screenshot.png")
print(result["heading"])
print(result["body_text"])

import anthropic
import base64
import json
from pathlib import Path
from dataclasses import dataclass

client = anthropic.Anthropic()


@dataclass
class UIValidationResult:
    passed: bool
    issues: list[str]
    regions_checked: list[str]


def validate_ui_screenshot(
    screenshot_path: str,
    expected_elements: list[str],
) -> UIValidationResult:
    """
    Verify that all expected UI elements are present and readable in a screenshot.
    Returns a structured result suitable for an agent decision loop.
    """
    img_bytes = Path(screenshot_path).read_bytes()
    img_b64 = base64.standard_b64encode(img_bytes).decode("utf-8")

    element_list = "\n".join(f"- {e}" for e in expected_elements)
    prompt = f"""This screenshot shows a UI. Verify that each of the following elements is
present and legible:

{element_list}

Return JSON with this exact shape:
{{
  "passed": true | false,
  "issues": ["<description of missing or broken element>", ...],
  "regions_checked": ["<element name>: <location description>", ...]
}}

- Set passed=true only if ALL elements are present and legible.
- If an element is missing or unreadable, add a clear description to issues.
- For each element, add a brief location description to regions_checked.
"""

    response = client.messages.create(
        model="claude-opus-4-5",
        max_tokens=1024,
        messages=[
            {
                "role": "user",
                "content": [
                    {
                        "type": "image",
                        "source": {
                            "type": "base64",
                            "media_type": "image/png",
                            "data": img_b64,
                        },
                    },
                    {"type": "text", "text": prompt},
                ],
            }
        ],
    )

    raw = json.loads(response.content[0].text)
    return UIValidationResult(
        passed=raw["passed"],
        issues=raw.get("issues", []),
        regions_checked=raw.get("regions_checked", []),
    )


# Usage in an agent loop:
def agent_verify_page(screenshot_path: str) -> None:
    result = validate_ui_screenshot(
        screenshot_path,
        expected_elements=[
            "Submit button",
            "Total amount field",
            "Terms of service checkbox",
        ],
    )
    if not result.passed:
        raise AssertionError(f"UI validation failed: {result.issues}")
    print("Validation passed. Elements found:", result.regions_checked)

import Anthropic from "@anthropic-ai/sdk";
import fs from "fs";

const client = new Anthropic(); // uses ANTHROPIC_API_KEY

async function extractChartData(imagePath) {
  const imageBuffer = fs.readFileSync(imagePath);
  const imageBase64 = imageBuffer.toString("base64");

  const response = await client.messages.create({
    model: "claude-opus-4-5",
    max_tokens: 1024,
    messages: [
      {
        role: "user",
        content: [
          {
            type: "image",
            source: {
              type: "base64",
              media_type: "image/png",
              data: imageBase64,
            },
          },
          {
            type: "text",
            text: `This is a bar chart or line chart image.
Extract the data series visible in the chart.
Return JSON with this shape:
{
  "chart_type": "bar | line | pie | other",
  "x_axis_label": "...",
  "y_axis_label": "...",
  "series": [
    { "name": "...", "data": [{ "x": "...", "y": <number> }, ...] }
  ]
}
Include only values that are clearly legible. Use null for ambiguous values.`,
          },
        ],
      },
    ],
  });

  return JSON.parse(response.content[0].text);
}

// Usage
const chartData = await extractChartData("revenue_chart.png");
console.log(JSON.stringify(chartData, null, 2));
